import type { PagesRender } from '../../render'

export const lazyRenderPagesPage: PagesRender = (...args) => {
  if (process.env.NEXT_MINIMAL) {
    throw new Error("Can't use lazyRenderPagesPage in minimal mode")
  } else {
    const render: PagesRender = (
      require('./module.compiled') as typeof import('./module.compiled')
    ).renderToHTML

    return render(...args)
  }
}

public async renderToHTML(
  req: ServerRequest,
  res: ServerResponse,
  pathname: string,
  query: ParsedUrlQuery = {}
): Promise<string | null> {
  return getTracer().trace(BaseServerSpan.renderToHTML, async () => {
    return this.renderToHTMLImpl(req, res, pathname, query)
  })
}

private async renderToHTMLImpl(
  req: ServerRequest,
  res: ServerResponse,
  pathname: string,
  query: ParsedUrlQuery = {}
): Promise<string | null> {
  return this.getStaticHTML((ctx) => this.renderToResponse(ctx), {
    req,
    res,
    pathname,
    query,
  })
}

public async renderError(
  err: Error | null,
  req: ServerRequest,
  res: ServerResponse,
  pathname: string,
  query: NextParsedUrlQuery = {},
  setHeaders = true
): Promise<void> {
  return getTracer().trace(BaseServerSpan.renderError, async () => {
    return this.renderErrorImpl(err, req, res, pathname, query, setHeaders)
  })
}

private async renderErrorImpl(
  err: Error | null,
  req: ServerRequest,
  res: ServerResponse,
  pathname: string,
  query: NextParsedUrlQuery = {},
  setHeaders = true
): Promise<void> {
  if (setHeaders) {
    res.setHeader(
      'Cache-Control',
      'private, no-cache, no-store, max-age=0, must-revalidate'
    )
  }

  return this.pipe(
    async (ctx) => {
      const response = await this.renderErrorToResponse(ctx, err)
      if (this.minimalMode && res.statusCode === 500) {
        throw err
      }
      return response
    },
    { req, res, pathname, query }
  )
}

